mapper.insert:
INSERT INTO notifications (
    user_id, type, title, message, channel, status, sent_at, read_at, metadata, created_at, updated_at
) VALUES (
    #{userId}, #{type}, #{title}, #{message}, #{channel}, #{status}, #{sentAt}, #{readAt},
    #{metadata}, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
)

mapper.select:
SELECT id, user_id, type, title, message, channel, status, sent_at, read_at, metadata, created_at, updated_at
FROM notifications
WHERE id = #{id}

SELECT id, user_id, type, title, message, channel, status, sent_at, read_at, metadata, created_at, updated_at
FROM notifications
WHERE user_id = #{userId}
ORDER BY created_at DESC
LIMIT #{page.size} OFFSET #{page.offset}

SELECT id, user_id, type, title, message, channel, status, sent_at, read_at, metadata, created_at, updated_at
FROM notifications
WHERE type = #{type}
ORDER BY created_at DESC
LIMIT #{page.size} OFFSET #{page.offset}

SELECT id, user_id, type, title, message, channel, status, sent_at, read_at, metadata, created_at, updated_at
FROM notifications
WHERE channel = #{channel}
ORDER BY created_at DESC
LIMIT #{page.size} OFFSET #{page.offset}

SELECT id, user_id, type, title, message, channel, status, sent_at, read_at, metadata, created_at, updated_at
FROM notifications
WHERE status = #{status}
ORDER BY created_at DESC
LIMIT #{page.size} OFFSET #{page.offset}

SELECT id, user_id, type, title, message, channel, status, sent_at, read_at, metadata, created_at, updated_at
FROM notifications
WHERE status = 'PENDING'
  AND channel = #{channel}
ORDER BY created_at ASC
LIMIT #{limit}

SELECT id, user_id, type, title, message, channel, status, sent_at, read_at, metadata, created_at, updated_at
FROM notifications
WHERE created_at BETWEEN #{startDate} AND #{endDate}
ORDER BY created_at DESC
LIMIT #{page.size} OFFSET #{page.offset}

mapper.update:
UPDATE notifications
SET status = #{status}, updated_at = CURRENT_TIMESTAMP
WHERE id = #{id}

UPDATE notifications
SET status = 'SENT', sent_at = #{sentAt}, updated_at = CURRENT_TIMESTAMP
WHERE id = #{id}

UPDATE notifications
SET status = 'READ', read_at = #{readAt}, updated_at = CURRENT_TIMESTAMP
WHERE id = #{id}

UPDATE notifications
SET status = 'FAILED', updated_at = CURRENT_TIMESTAMP
WHERE id = #{id}

mapper.delete:
DELETE FROM notifications 
WHERE user_id = #{userId}
  AND created_at < #{olderThan}

mapper.select:
SELECT COUNT(*)
FROM notifications
WHERE user_id = #{userId}

SELECT COUNT(*)
FROM notifications
WHERE status = #{status}

SELECT COUNT(*)
FROM notifications
WHERE type = #{type}

SELECT COUNT(*)
FROM notifications
WHERE channel = #{channel}

SELECT id, user_id, type, title, message, channel, status, sent_at, read_at, metadata, created_at, updated_at
FROM notifications
WHERE status = 'FAILED'
  AND (metadata->>'retryCount')::int < #{maxRetryCount}
ORDER BY created_at ASC
LIMIT #{limit}
